def char_ngrams(s, n=3):
    s = normalize_ar(s).replace(" ", "")
    return set(s[i:i+n] for i in range(len(s)-n+1))

def jaccard(a, b, n=3):
    A = char_ngrams(a, n)
    B = char_ngrams(b, n)
    if not A and not B:
        return 1.0
    if not A or not B:
        return 0.0
    return len(A & B) / len(A | B)

