# Implement Jaro-Winkler similarity for strings
def jaro_distance(s1, s2):
    s1 = normalize_ar(s1).replace(" ", "")
    s2 = normalize_ar(s2).replace(" ", "")
    if s1 == s2:
        return 1.0
    len1 = len(s1)
    len2 = len(s2)
    max_dist = max(len1, len2)//2 - 1
    match = 0
    hash_s1 = [0]*len1
    hash_s2 = [0]*len2

    for i in range(len1):
        start = max(0, i - max_dist)
        end = min(i + max_dist + 1, len2)
        for j in range(start, end):
            if s2[j] == s1[i] and hash_s2[j] == 0:
                hash_s1[i] = 1
                hash_s2[j] = 1
                match += 1
                break
    if match == 0:
        return 0.0
    t = 0
    point = 0
    for i in range(len1):
        if hash_s1[i]:
            while hash_s2[point] == 0:
                point += 1
            if s1[i] != s2[point]:
                t += 1
            point += 1
    t = t // 2
    return (match/len1 + match/len2 + (match - t)/match)/3.0

def jaro_winkler(s1, s2, p=0.1):
    s1n = normalize_ar(s1).replace(" ", "")
    s2n = normalize_ar(s2).replace(" ", "")
    j = jaro_distance(s1, s2)
    # common prefix length up to 4
    prefix = 0
    for c1, c2 in zip(s1n, s2n):
        if c1 == c2:
            prefix += 1
        else:
            break
        if prefix == 4:
            break
    return j + prefix * p * (1 - j)

